package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetEscapeCharacter_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character escape = format.getEscapeCharacter();
        assertNull(escape, "Default format escapeCharacter should be null");
    }

    @Test
    void testGetEscapeCharacter_InformixUnload() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD;
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "InformixUnload format escapeCharacter should not be null");
        assertEquals(Character.valueOf('\\'), escape, "Escape character should be backslash");
    }

    @Test
    void testGetEscapeCharacter_MySQL() {
        CSVFormat format = CSVFormat.MYSQL;
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "MySQL format escapeCharacter should not be null");
        assertEquals(Character.valueOf('\\'), escape, "Escape character should be backslash");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeCharSet() {
        CSVFormat base = CSVFormat.DEFAULT;
        CSVFormat format = base.withEscape(Character.valueOf('!'));
        Character escape = format.getEscapeCharacter();
        assertNotNull(escape, "Escape character should not be null after withEscape");
        assertEquals(Character.valueOf('!'), escape, "Escape character should be '!'");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeCharSet_Null() {
        CSVFormat base = CSVFormat.DEFAULT.withEscape(Character.valueOf('!'));
        CSVFormat format = base.withEscape((Character) null);
        Character escape = format.getEscapeCharacter();
        assertNull(escape, "Escape character should be null after setting withEscape(null)");
    }
}
